static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &                  tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Mistral Instruct v0.3 format:
    //   <s>[INST] {system}\n\n{user} [/INST]{assistant}</s>[INST] {user} [/INST]
    // System messages are collected and prepended to the first user turn with a blank
    // line separator. Subsequent non-system messages pass through unchanged.
    auto adjusted_messages = json::array();
    std::string pending_system;
    for (const auto & msg : inputs.messages) {
        const auto role = msg.value("role", "");
        if (role == "system") {
            if (!pending_system.empty()) {
                pending_system += "\n\n";
            }
            pending_system += msg.value("content", "");
        } else if (role == "user" && !pending_system.empty()) {
            auto adjusted       = msg;
            adjusted["content"] = pending_system + "\n\n" + msg.value("content", "");
            adjusted_messages.push_back(adjusted);
            pending_system.clear();
        } else {
            adjusted_messages.push_back(msg);
        }
    }

    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs, /* messages_override = */ adjusted_messages);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    auto include_grammar = false;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        // Response format (JSON schema) parser
        if (inputs.json_schema.is_object() && !inputs.json_schema.empty()) {
            include_grammar = true;
            return p.literal(inputs.generation_prompt) +
                   p.content(p.schema(p.json(), "response-format", inputs.json_schema));
        }

        // Content-only parser
        return p.literal(inputs.generation_prompt) + p.content(p.rest());
    });

    data.parser = parser.save();

    if (include_grammar) {
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            parser.build_grammar(builder, false);
        });
    }

    return data;
}

namespace workaround {

static void map_developer_role_to_system(json & messages) {
    for (auto & message : messages) {
        if (message.contains("role")) {
            if (message["role"] == "developer") {
                message["role"] = "system";
            }
        }
    }
}


